mapper.sql:
FROM alert a
LEFT JOIN panel p ON p.panel_id = a.panel_id
LEFT JOIN circuit c ON c.circuit_id = a.circuit_id


        AND a.status = #{status}


        AND a.type = #{type}


        AND p.site_id = #{siteId}


        AND a.triggered_at >= #{fromAt}


        AND a.triggered_at < #{toAt}


        AND EXISTS (
            SELECT 1
            FROM user_site us
            WHERE us.user_id = #{userId}
              AND us.site_id = p.site_id
              AND us.deleted_at IS NULL
        )
